// epsilon is used for floating‑point comparisons that are not exact.
const epsilon = 1e-9

// TestUnitOrderCalculateTotalEdgeCases adds a handful of edge‑case
// scenarios that are **not** covered by the existing suite
// (TestUnitOrderCalculateTotal, TestUnitOrderCalculateTotalEmpty, …).
//
// The test is table‑driven and each sub‑test checks that
//   * `CalculateTotal` never panics (even with a nil slice),
//   * the resulting `Total` field is set correctly,
//   * the method does **not** modify the items themselves.
//
// The sub‑tests deliberately exercise situations that are
// unlikely in normal business flow but are still valid from a
// pure‑calculation point of view: zero price, zero quantity,
// negative price, extremely large numbers and a nil `Items` slice.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	tests := []struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		preSetTotal float64 // value that already lives in o.Total before calling CalculateTotal
	}{
		{
			name: "zero_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
			},
			wantTotal: 0,
		},
		{
			name: "zero_quantity",
			items: []OrderItem{
				{ProductID: 2, Quantity: 0, Price: 123.45},
			},
			wantTotal: 0,
		},
		{
			name: "negative_price",
			items: []OrderItem{
				{ProductID: 3, Quantity: 2, Price: -50},
				{ProductID: 4, Quantity: 1, Price: 30},
			},
			// (-50 * 2) + (30 * 1) = -70
			wantTotal: -70,
		},
		{
			name: "large_numbers",
			items: []OrderItem{
				{ProductID: 5, Quantity: 1_000_000, Price: 1_000_000},
			},
			// 1 000 000 * 1 000 000 = 1 000 000 000 000
			wantTotal: 1_000_000_000_000,
		},
		{
			name:        "nil_items_slice",
			items:       nil,
			wantTotal:   0,
			preSetTotal: 999, // make sure the method overwrites an existing value
		},
		{
			name: "duplicate_product_ids",
			items: []OrderItem{
				{ProductID: 7, Quantity: 1, Price: 10},
				{ProductID: 7, Quantity: 2, Price: 10},
			},
			// (1+2) * 10 = 30
			wantTotal: 30,
		},
		{
			name: "high_precision_price",
			items: []OrderItem{
				{ProductID: 8, Quantity: 3, Price: 0.3333333333333333},
			},
			// 3 * 0.3333333333333333 = 0.9999999999999999 (≈ 1)
			wantTotal: 0.9999999999999999,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Arrange – create an Order with the supplied items.
			o := Order{
				Items: tt.items,
				// pre‑populate Total to verify that CalculateTotal overwrites it.
				Total: tt.preSetTotal,
			}

			// Act – calculate the total. The method must never panic,
			// even when o.Items is nil.
			o.CalculateTotal()

			// Assert – the Total field must be equal (within epsilon) to the expected value.
			if diff := math.Abs(o.Total - tt.wantTotal); diff > epsilon {
				t.Fatalf("unexpected total: got %v, want %v (diff %v > %v)",
					o.Total, tt.wantTotal, diff, epsilon)
			}

			// Additionally ensure that the slice of items has not been altered.
			if len(o.Items) != len(tt.items) {
				t.Fatalf("items slice length changed: got %d, want %d", len(o.Items), len(tt.items))
			}
			for i := range o.Items {
				if o.Items[i] != tt.items[i] {
					t.Fatalf("item %d changed: got %+v, want %+v", i, o.Items[i], tt.items[i])
				}
			}
		})
	}
}
