## 3. Как исправить

### 3.1. Сделать запрос Unicode‑agnostic

Самый надёжный способ – **привести обе стороны к одному регистру** и использовать `COLLATE NOCASE` (для ASCII) + `UPPER()` (для Unicode). Пример реализации в `repository/sqlite/product.go`:

```go
// Search ищет в названиях и описаниях, игнорируя регистр Unicode.
func (r *sqliteProductRepository) Search(ctx context.Context, query string, limit int) ([]*entity.Product, error) {
    // Если limit == 0 → используем дефолт 20 (как в usecase)
    if limit <= 0 {
        limit = 20
    }

    // Приводим запрос к верхнему регистру и оборачиваем в %…%
    q := "%" + strings.ToUpper(query) + "%"

    rows, err := r.db.QueryContext(
        ctx,
        `SELECT id, category_id, name, description, price, image_url, in_stock,
                created_at, updated_at
         FROM products
         WHERE UPPER(name) LIKE ? OR UPPER(description) LIKE ?
         ORDER BY id ASC
         LIMIT ?`,
        q, q, limit,
    )
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var out []*entity.Product
    for rows.Next() {
        p := new(entity.Product)
        if err := rows.Scan(&p.ID, &p.CategoryID, &p.Name, &p.Description,
            &p.Price, &p.ImageURL, &p.InStock, &p.CreatedAt, &p.UpdatedAt); err != nil {
            return nil, err
        }
        out = append(out, p)
    }
    return out, rows.Err()
}
```

