## Конкретные шаги по оптимизации  

### 1. Сократить количество открытий SQLite‑БД  
**Что делаем:** вместо `setupTestDB(t)` в каждом репозитори‑тесте открывать новую БД, создаём **одну** базу на пакет и откатываем транзакцию после каждого теста.  

**Как:**  

```go
// repository/repository_test.go  (new файл)
package repository_test

import (
    "database/sql"
    "testing"

    _ "github.com/mattn/go-sqlite3"
    "github.com/yourorg/beanbrew/internal/sqlite"
)

var (
    db   *sql.DB
    once sync.Once
)

func TestMain(m *testing.M) {
    // Открываем одну in‑memory БД и делаем миграции один раз
    var err error
    db, err = sql.Open("sqlite3", ":memory:")
    if err != nil {
        panic(err)
    }
    if err = sqlite.RunMigrations(db); err != nil {
        panic(err)
    }
    code := m.Run()
    db.Close()
    os.Exit(code)
}

// helper для каждого теста
func withTx(t *testing.T, fn func(tx *sql.Tx)) {
    t.Helper()
    tx, err := db.Begin()
    if err != nil {
        t.Fatalf("begin tx: %v", err)
    }
    defer func() {
        // откатываем, даже если тест упал
        _ = tx.Rollback()
    }()
    fn(tx)
}
```

