//   * that the method overwrites a pre‑filled Total field
//
// The cases below focus on the behaviour of the pure arithmetic when the
// input data contains “odd” values – zero / negative quantities, zero prices,
// and extreme values that push the limits of float64.
//
// Naming follows the project convention: TestUnitOrder_<Method>_<Scenario>.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	type testCase struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsNaN   bool // true → expect math.IsNaN(total)
		wantIsInf   bool // true → expect math.IsInf(total, +1)
		tolerance   float64
		description string // optional – only for readability in the table
	}

	cases := []testCase{
		{
			name: "ZeroQuantity_Ignored",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 5, Price: 10.0},
			},
			// 0*123.45 + 5*10 = 50
			wantTotal: 50.0,
			tolerance: 1e-9,
		},
		{
			name: "NegativeQuantity_AllowedByCalc",
			// Validation would reject this, but CalculateTotal is a pure
			// arithmetic helper – we still want to guarantee the math works.
			items: []OrderItem{
				{ProductID: 1, Quantity: -3, Price: 20.0},
				{ProductID: 2, Quantity: 2, Price: 15.0},
			},
			// (-3)*20 + 2*15 = -60 + 30 = -30
			wantTotal: -30.0,
			tolerance: 1e-9,
		},
		{
			name: "ZeroPrice_Ignored",
			items: []OrderItem{
				{ProductID: 1, Quantity: 10, Price: 0.0},
				{ProductID: 2, Quantity: 3, Price: 7.5},
			},
			// 10*0 + 3*7.5 = 22.5
			wantTotal: 22.5,
			tolerance: 1e-9,
		},
		{
			name: "MixedZeroAndNegative",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 99.99},
				{ProductID: 2, Quantity: -2, Price: 5.0},
				{ProductID: 3, Quantity: 4, Price: 0.0},
			},
			// 0*99.99 + (-2)*5 + 4*0 = -10
			wantTotal: -10.0,
			tolerance: 1e-9,
		},
		{
			name: "HugeValues_NoOverflow",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1_000_000, Price: 1_000_000.0},
				{ProductID: 2, Quantity: 2_000_000, Price: 2_000_000.0},
			},
			// 1e6*1e6 + 2e6*2e6 = 1e12 + 4e12 = 5e12
			wantTotal: 5e12,
			tolerance: 1e-3, // a tiny relative tolerance is enough for such large numbers
		},
		{
			name: "PriceNaN_PropagatesNaN",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
			},
			wantIsNaN: true,
		},
		{
		 name: "PriceInf_PropagatesInf",
		 items: []OrderItem{
			 {ProductID: 1, Quantity: 1, Price: math.Inf(1)},
		 },
		 wantIsInf: true,
		},
	}

	for _, tc := range cases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()

			// Build the order – the ID/CustomerID fields are irrelevant for the
			// calculation, so we keep them zero‑valued.
			o := Order{
				Items: tc.items,
			}

			o.CalculateTotal()

			if tc.wantIsNaN {
				require.True(t, math.IsNaN(o.Total), "expected Total to be NaN")
				return
			}
			if tc.wantIsInf {
				require.True(t, math.IsInf(o.Total, +1), "expected Total to be +Inf")
				return
			}

			// Normal numeric comparison – allow a tiny tolerance because the
			// method uses plain float64 multiplication/addition.
			if tc.tolerance == 0 {
				tc.tolerance = 1e-9
			}
			diff := math.Abs(o.Total - tc.wantTotal)
			require.LessOrEqual(t, diff, tc.tolerance,
				"Total mismatch: got %v, want %v (diff %v > tol %v)",
				o.Total, tc.wantTotal, diff, tc.tolerance)
		})
	}
}
