func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// Таблица тест‑кейсов.  Каждый кейс описывает набор OrderItem‑ов,
	// ожидаемое значение Total и комментарий, почему он интересен.
	tests := []struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantInf     bool // ожидаем бесконечность (overflow)
		wantNaN     bool // ожидаем NaN (например, NaN‑price)
		prepareFunc func(o *Order) // опциональная модификация Order после расчёта
	}{
		{
			name: "zero_price_items",
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
