			},
			// Суммируем отрицательные цены – результат тоже отрицательный.
			wantTotal: -25,
		},
		{
			name: "zero_quantity_items",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 100},
				{ProductID: 2, Quantity: 0, Price: 200},
			},
			// Quantity == 0 не вносит вклада в сумму.
			wantTotal: 0,
		},
		{
			name: "nil_items_slice",
			// items == nil (не инициализированный срез)
			items:     nil,
			wantTotal: 0,
		},
		{
			name: "large_quantity_and_price_overflow",
			items: []OrderItem{
				// 1e154 * 1e154 = 1e308, умножаем ещё раз → Inf
				{ProductID: 1, Quantity: int(math.MaxInt64), Price: 1e154},
			},
			wantInf: true,
		},
		{
			name: "price_is_nan",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
			},
			wantNaN: true,
		},
		{
			name: "recalculate_after_items_change",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: 100},
			},
			wantTotal: 100,
			prepareFunc: func(o *Order) {
				// Меняем один из элементов и вызываем CalculateTotal ещё раз.
				o.Items[0].Quantity = 3 // теперь 3 * 100 = 300
				o.CalculateTotal()
			},
			// После повторного расчёта ожидаем 300.
			wantTotal: 300,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := &Order{
				Items: tt.items,
