					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}

			if o.Total != tt.wantTotal {
				t.Fatalf("unexpected Total: want %v, got %v", tt.wantTotal, o.Total)
			}

			// Если в кейсе указана дополнительная подготовка,
			// выполняем её и проверяем результат ещё раз.
			if tt.prepareFunc != nil {
				tt.prepareFunc(o)
				if o.Total != tt.wantTotal {
					t.Fatalf("after re‑calculation: want %v, got %v", tt.wantTotal, o.Total)
				}
			}
		})
	}
