	// 2️⃣ Создаём категорию (используем уже существующий хелпер)
	catID := testhelper.CreateCategory(t, srv.URL, "Кофе", "coffee", "Кофейные напитки")

	// 3️⃣ Добавляем товар в эту категорию
	const lattePrice = 350.0
	prodID := testhelper.CreateProduct(t, srv.URL, domain.Product{
		CategoryID:  catID,
		Name:        "Латте",
		Description: "Кофе с молоком",
		Price:       lattePrice,
		ImageURL:    "https://example.com/latte.png",
		InStock:     true,
	})

	// 4️⃣ Оформляем заказ (2 шт. продукта)
	orderPayload := map[string]any{
		"customer_id": "alice@example.com",
		"items": []map[string]any{
			{
				"product_id": prodID,
				"quantity":   2,
			},
		},
	}
	resp := testhelper.PostJSON(t, srv.URL+"/orders", orderPayload)
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected status %d, got %d", http.StatusCreated, resp.StatusCode)
	}
	var createdOrder struct {
		ID        int64   `json:"id"`
		CustomerID string `json:"customer_id"`
		Status    string  `json:"status"`
		Total     float64 `json:"total"`
	}
	testhelper.DecodeBody(t, resp, &createdOrder)

	// проверяем, что статус «new» и сумма посчитана правильно
	if createdOrder.Status != string(domain.OrderStatusNew) {
		t.Fatalf("expected order status %q, got %q", domain.OrderStatusNew, createdOrder.Status)
	}
	expectedTotal := lattePrice * 2 // 350 * 2 = 700
	if createdOrder.Total != expectedTotal {
		t.Fatalf("expected total %.2f, got %.2f", expectedTotal, createdOrder.Total)
	}

	// 5️⃣ Обрабатываем заказ – POST /orders/{id}/process
	processURL := srv.URL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/process"
	resp = testhelper.PostJSON(t, processURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("process: expected status %d, got %d", http.StatusOK, resp.StatusCode)
	}
	var procResp struct {
		Status string `json:"status"`
	}
	testhelper.DecodeBody(t, resp, &procResp)
	if procResp.Status != string(domain.OrderStatusProcessing) {
		t.Fatalf("expected status %q after process, got %q", domain.OrderStatusProcessing, procResp.Status)
	}

	// 6️⃣ Завершаем заказ – POST /orders/{id}/complete
	completeURL := srv.URL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/complete"
	resp = testhelper.PostJSON(t, completeURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("complete: expected status %d, got %d", http.StatusOK, resp.StatusCode)
	}
	var compResp struct {
		Status string `json:"status"`
	}
	testhelper.DecodeBody(t, resp, &compResp)
	if compResp.Status != string(domain.OrderStatusCompleted) {
		t.Fatalf("expected status %q after complete, got %q", domain.OrderStatusCompleted, compResp.Status)
	}

	// 7️⃣ Финальная проверка – GET /orders/{id}
	getURL := srv.URL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10)
	resp = testhelper.Get(t, getURL)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("final GET: expected status %d, got %d", http.StatusOK, resp.StatusCode)
	}
	var finalOrder struct {
		ID        int64   `json:"id"`
		CustomerID string `json:"customer_id"`
		Status    string  `json:"status"`
		Total     float64 `json:"total"`
	}
	testhelper.DecodeBody(t, resp, &finalOrder)

	if finalOrder.Status != string(domain.OrderStatusCompleted) {
		t.Fatalf("final order status expected %q, got %q", domain.OrderStatusCompleted, finalOrder.Status)
	}
	if finalOrder.Total != expectedTotal {
		t.Fatalf("final order total expected %.2f, got %.2f", expectedTotal, finalOrder.Total)
	}
}
